from flask import Flask, request, jsonify
import redis
import os
import hmac
import hashlib
from functools import wraps

app = Flask(__name__)

# Redis connection with secure configuration
redis_client = redis.Redis(
    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=int(os.environ.get('REDIS_PORT', 6379)),
    password=os.environ.get('REDIS_PASSWORD'),
    ssl=os.environ.get('REDIS_SSL', 'false').lower() == 'true',
    ssl_cert_reqs='required' if os.environ.get('REDIS_SSL', 'false').lower() == 'true' else None,
    decode_responses=True
)

# API key for authentication
API_KEY = os.environ.get('ADMIN_API_KEY')
if not API_KEY:
    raise ValueError("ADMIN_API_KEY environment variable must be set")

# Explicit allowlist of permitted Redis commands
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'KEYS',
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LRANGE', 'LLEN',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER',
    'ZADD', 'ZREM', 'ZRANGE', 'ZCARD',
    'PING', 'DBSIZE', 'INFO', 'FLUSHDB'
}

# Commands that require additional validation
DANGEROUS_COMMANDS = {'FLUSHDB', 'FLUSHALL', 'KEYS', 'CONFIG', 'SHUTDOWN', 'SCRIPT'}


def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        provided_key = request.headers.get('X-API-Key')
        if not provided_key:
            return jsonify({'error': 'API key required'}), 401
        
        if not hmac.compare_digest(provided_key, API_KEY):
            return jsonify({'error': 'Invalid API key'}), 403
        
        return f(*args, **kwargs)
    return decorated_function


def validate_command(command_str):
    if not command_str or not isinstance(command_str, str):
        return False, "Command must be a non-empty string"
    
    parts = command_str.strip().split()
    if not parts:
        return False, "Empty command"
    
    cmd = parts[0].upper()
    
    if cmd not in ALLOWED_COMMANDS:
        return False, f"Command '{cmd}' is not allowed"
    
    if cmd in DANGEROUS_COMMANDS:
        confirmation = request.args.get('confirm')
        if confirmation != 'yes':
            return False, f"Command '{cmd}' requires confirmation parameter 'confirm=yes'"
    
    if cmd == 'KEYS' and len(parts) > 1 and parts[1] == '*':
        return False, "KEYS * is not allowed for performance reasons. Use a specific pattern."
    
    return True, None


@app.route('/api/redis/execute', methods=['POST'])
@require_api_key
def execute_redis_command():
    try:
        command = request.args.get('command')
        
        if not command:
            return jsonify({'error': 'Missing command parameter'}), 400
        
        is_valid, error_msg = validate_command(command)
        if not is_valid:
            return jsonify({'error': error_msg}), 400
        
        parts = command.strip().split()
        
        result = redis_client.execute_command(*parts)
        
        return jsonify({
            'success': True,
            'command': command,
            'result': result
        }), 200
        
    except redis.exceptions.ResponseError as e:
        return jsonify({
            'success': False,
            'error': f'Redis error: {str(e)}'
        }), 400
    except redis.exceptions.ConnectionError as e:
        return jsonify({
            'success': False,
            'error': 'Redis connection error'
        }), 503
    except Exception as e:
        return jsonify({
            'success': False,
            'error': 'Internal server error'
        }), 500


@app.route('/api/redis/allowed-commands', methods=['GET'])
@require_api_key
def get_allowed_commands():
    return jsonify({
        'allowed_commands': sorted(list(ALLOWED_COMMANDS)),
        'dangerous_commands': sorted(list(DANGEROUS_COMMANDS))
    }), 200


@app.route('/health', methods=['GET'])
def health_check():
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'}), 200
    except:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected'}), 503


if __name__ == '__main__':
    app.run(
        host='127.0.0.1',
        port=5000,
        debug=False,
        ssl_context='adhoc' if os.environ.get('USE_SSL', 'false').lower() == 'true' else None
    )